SELECT sc.id, sc.account, sc.avatar_url, sc.username, sc.nick_name, sc.email, sc.phone, sc.following_num, sc.followers_num, sc.posts_num, sc.like_avg_num, sc.comment_avg_num, sc.play_avg_num, sc.tag, sc.description, sc.country, sc.platform_type, sc.keyword, sc.new_tag, sc.face_status, sc.del_flag, sc.kol_price_min, sc.kol_price_max, sc.dislike_tags, sc.like_tags, sc.remark, sc.create_by, sc.create_time, sc.update_by, sc.update_time, sc.is_tag_confirm, sc.star, sc.gender, sc.age, ssc.id AS collection_id FROM store_celebrity sc LEFT JOIN ( SELECT id, celebrity_id FROM store_seller_collection WHERE 1=1
AND seller_id = #{storeCelebrityModel.sellerId}
) ssc ON ssc.celebrity_id = sc.id where sc.del_flag = 0 and avatar_url != '' and email != ''
and sc.platform_type = #{storeCelebrityModel.platformType}
and sc.account like '%${storeCelebrityModel.account}%'
and sc.phone like '%${storeCelebrityModel.phone}%'
AND find_in_set('${item}',like_tags)
AND find_in_set('${item}',dislike_tags)
and sc.star=#{storeCelebrityModel.star}
and sc.is_tag_confirm=#{storeCelebrityModel.isTagConfirm}
and sc.nick_name like '%${storeCelebrityModel.nickName}%'
and sc.email like '%${storeCelebrityModel.email}%'
and sc.description like '%${storeCelebrityModel.description}%'
and sc.username like '%${storeCelebrityModel.username}%'
and sc.country = #{storeCelebrityModel.country}
and sc.followers_num >= #{storeCelebrityModel.followersStartNum}
and sc.followers_num <= #{storeCelebrityModel.followersEndNum}
and sc.posts_num >= #{storeCelebrityModel.postsStartNum}
and sc.posts_num <= #{storeCelebrityModel.postsEndNum}
and sc.like_avg_num >= #{storeCelebrityModel.likeAvgStartNum}
and sc.like_avg_num <= #{storeCelebrityModel.likeAvgEndNum}
and sc.comment_avg_num >= #{storeCelebrityModel.commentAvgStartNum}
and sc.comment_avg_num <= #{storeCelebrityModel.commentAvgEndNum}
and sc.play_avg_num >= #{storeCelebrityModel.playAvgStartNum}
and sc.play_avg_num <= #{storeCelebrityModel.playAvgEndNum}
and sc.face_status = #{storeCelebrityModel.faceStatus}
and sc.remark = #{storeCelebrityModel.remark}
and IF(smp.send_email_count is null ,0,smp.send_email_count)=#{storeCelebrityModel.sendEmailCount}
and sc.gender = #{storeCelebrityModel.gender}
and (sc.gender <= -1 or sc.gender is null)
and DATE_FORMAT(sc.create_time, '%Y-%m-%d') >= DATE_FORMAT(#{storeCelebrityModel.startCreateTime}, '%Y-%m-%d')
and DATE_FORMAT(sc.create_time, '%Y-%m-%d') <= DATE_FORMAT(#{storeCelebrityModel.endCreateTime}, '%Y-%m-%d')
AND followers_num > 1000
order by sc.create_time desc

