order by sc.create_time desc

SELECT id, account, avatar_url, username, nick_name, followers_num, play_avg_num, tag, star, country, like_tags, platform_type, del_flag, remark, create_by, create_time, update_by, update_time, verify_Result, gender, approved_status, verify_user_id
FROM store_celebrity where del_flag = 0
and followers_num >= #{storeCelebrityModel.followersStartNum}
and followers_num <= #{storeCelebrityModel.followersEndNum}
and nick_name like '%${storeCelebrityModel.nickName}%'
and verify_result is null
and verify_result = #{storeCelebrityModel.verifyResult}
and verify_user_id = #{storeCelebrityModel.verifyUserId}
and (like_tags is null or like_tags = '')
and (country is null or country = '')
and platform_type = #{storeCelebrityModel.platformType}
order by create_time DESC

